function.body:
Cur_Params          RECORD;
    p_record_id         VARCHAR(60);
    v_Today             DATE := now()::DATE; 

    -- Variables de control
    v_DocBaseType       VARCHAR(60);
    v_CheckAuth         CHAR(1);
    v_CheckElec         CHAR(1);
    v_MovementDate      DATE;
    v_DocStatus         VARCHAR(60);
    v_IsSOTrx           CHAR(1); 
    v_Processed         CHAR(1);

BEGIN
    -- 1. Obtener ID del registro
    FOR Cur_Params IN (
        SELECT * FROM ad_ep_instance_para WHERE ad_ep_instance_id = p_ep_instance
    ) LOOP
        IF (cur_params.parametername = 'Record_ID') THEN
            p_record_id := cur_params.p_string;
        END IF;
    END LOOP;

    IF (p_record_id IS NULL) THEN RETURN; END IF;

    -- =======================================================================
    -- CASO 1: M_INOUT (Albaranes)
    -- =======================================================================
    SELECT 
        i.MovementDate, i.DocStatus, i.IsSOTrx, dt.DocBaseType, 
        COALESCE(dt.EM_Sswh_Implementautoriza, 'N')
    INTO 
        v_MovementDate, v_DocStatus, v_IsSOTrx, v_DocBaseType, v_CheckAuth
    FROM M_InOut i
    JOIN C_DocType dt ON i.C_DocType_ID = dt.C_DocType_ID
    WHERE i.M_InOut_ID = p_record_id;

    IF FOUND THEN
        IF (v_IsSOTrx = 'Y' AND v_DocBaseType = 'MMS' AND v_CheckAuth = 'Y') THEN
            IF (v_MovementDate::DATE <> v_Today) THEN
                -- Secuencia de actualización forzada (Desbloquear -> Actualizar -> Bloquear)
                UPDATE M_InOut SET Processed = 'N' WHERE M_InOut_ID = p_record_id;
                UPDATE M_InOut SET MovementDate = v_Today WHERE M_InOut_ID = p_record_id;
                UPDATE M_InOut SET Processed = 'Y' WHERE M_InOut_ID = p_record_id;
            END IF;
        END IF;
        RETURN;
    END IF;

    -- =======================================================================
    -- CASO 2: M_MOVEMENT (Movimientos de Inventario)
    -- =======================================================================
    SELECT 
        m.MovementDate, m.Processed, dt.DocBaseType, 
        COALESCE(dt.EM_Eei_Is_Edoc, 'N')
    INTO 
        v_MovementDate, v_Processed, v_DocBaseType, v_CheckElec
    FROM M_Movement m
    JOIN C_DocType dt ON m.em_ssrs_c_doctype_id = dt.C_DocType_ID
    WHERE m.M_Movement_ID = p_record_id;

    IF FOUND THEN
        IF (v_DocBaseType = 'MMM' AND v_CheckElec = 'Y') THEN
            IF (v_MovementDate::DATE <> v_Today) THEN

                -- Secuencia de actualización forzada
                UPDATE M_Movement SET Processed = 'N' WHERE M_Movement_ID = p_record_id;
                UPDATE M_Movement SET MovementDate = v_Today WHERE M_Movement_ID = p_record_id;

                -- Restaurar bloqueo solo si estaba procesado
                IF (v_Processed = 'Y') THEN
                    UPDATE M_Movement SET Processed = 'Y' WHERE M_Movement_ID = p_record_id;
                END IF;

            END IF;
        END IF;
    END IF;

EXCEPTION WHEN OTHERS THEN
    RETURN;
END EEI_CUSOFT_UPDATE
